from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    subject_map = {}
    for triple in triples:
        if triple.subject not in subject_map:
            subject_map[triple.subject] = []
        subject_map[triple.subject].append((triple.predicate, triple.object))

    # Find the main subject (likely an airport)
    main_subject = next(iter(subject_map.keys())) if subject_map else ""
    sentence = main_subject

    # Track relationships to build complex sentences
    city_served = None
    country = None
    location = None
    runway_info = []
    elevation_info = []
    identifiers = []
    other_info = []

    for subject, triples in subject_map.items():
        for predicate, obj in triples:
            if predicate == "cityServed":
                city_served = obj
            elif predicate == "country":
                country = obj
            elif predicate == "location":
                location = obj
            elif predicate == "elevationAboveTheSeaLevel":
                elevation_info.append(f"{obj} metres above sea level")
            elif predicate == "elevationAboveTheSeaLevelInFeet":
                elevation_info.append(f"{obj} feet above sea level")
            elif predicate == "runwayLength":
                runway_info.append(f"runway length of {obj} metres")
            elif predicate == "1stRunwayLengthFeet":
                runway_info.append(f"first runway length of {obj} feet")
            elif predicate == "3rdRunwayLengthFeet":
                runway_info.append(f"third runway length of {obj} feet")
            elif predicate == "icaoLocationIdentifier":
                identifiers.append(f"ICAO identifier {obj}")
            elif predicate == "locationIdentifier":
                identifiers.append(f"location identifier {obj}")
            elif predicate == "iataLocationIdentifier":
                identifiers.append(f"IATA identifier {obj}")
            elif predicate == "runwayName":
                runway_info.append(f"runway name {obj}")
            elif predicate == "runwaySurfaceType":
                runway_info.append(f"runway surface type {obj}")
            elif predicate == "1stRunwaySurfaceType":
                runway_info.append(f"first runway surface type {obj}")
            elif predicate == "4thRunwaySurfaceType":
                runway_info.append(f"fourth runway surface type {obj}")
            elif predicate == "5thRunwaySurfaceType":
                runway_info.append(f"fifth runway surface type {obj}")
            elif predicate == "operatingOrganisation":
                other_info.append(f"operated by {obj}")
            elif predicate == "owner":
                other_info.append(f"owned by {obj}")
            elif predicate == "mayor":
                other_info.append(f"has a mayor {obj}")
            elif predicate == "capital":
                other_info.append(f"has a capital of {obj}")
            elif predicate == "language":
                other_info.append(f"has an official language of {obj}")
            elif predicate == "leader":
                other_info.append(f"has a leader {obj}")
            elif predicate == "nativeName":
                other_info.append(f"has a native name {obj}")
            elif predicate == "isPartOf":
                other_info.append(f"is part of {obj}")
            elif predicate == "leaderParty":
                other_info.append(f"has a leader party {obj}")

    # Build a more natural sentence structure
    if city_served:
        sentence += f" serves the city of {city_served}"
        if location:
            sentence += f", located in {location}"
        if country:
            sentence += f", which is in {country}"

    # Add elevation if available
    if elevation_info:
        sentence += f" with an elevation of {elevation_info[0]}"

    # Add runway information
    if runway_info:
        sentence += f" featuring "
        sentence += ", ".join(runway_info[:-1]) if len(runway_info) > 1 else runway_info[0]
        if len(runway_info) > 1:
            sentence += f" and {runway_info[-1]}"

    # Add identifiers
    if identifiers:
        sentence += f" with "
        sentence += ", ".join(identifiers[:-1]) if len(identifiers) > 1 else identifiers[0]
        if len(identifiers) > 1:
            sentence += f" and {identifiers[-1]}"

    # Add other information
    if other_info:
        sentence += " and "
        sentence += ", ".join(other_info[:-1]) if len(other_info) > 1 else other_info[0]
        if len(other_info) > 1:
            sentence += f" and {other_info[-1]}"

    return sentence + "."
